var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GUEST_VOICE_NULL_A","text":{"KOREA":"흐윽…….","JPN":"ううっ……","ENG":"*Sob*","TWN":"嗚嗚……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"오구. 그랬어요~ 토닥토닥.","JPN":"あらあら。そうだったの～よしよし。","ENG":"Aww. I see. You did nothing wrong.","TWN":"原來是這樣～拍拍"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GUEST_VOICE_NULL_A","text":{"KOREA":"으허어엉.","JPN":"うわああああん。","ENG":"*Cry*","TWN":"嗚嗚嗚嗚嗚。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"자아. 이제 뚝! 하고 눈물 닦자. 여기 손수건 빌려줄…….","JPN":"さあ。もう泣かないの！　涙を拭って。ハンカチを貸してあげ……","ENG":"Stop crying. Here, use my handkerchief...","TWN":"好了，別哭了。來擦擦眼淚。這個手帕借……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GUEST_VOICE_NULL_A","text":{"KOREA":"크흥. 훌쩍.","JPN":"ぐすっ、チーン。","ENG":"*Sniffle* *Blows nose*","TWN":"嗚嗚。(擤鼻涕)"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"……아니, 줄게. 가져가렴.","JPN":"……いえ、それはあげるわ。持って行ってちょうだい。","ENG":"... You can keep it.","TWN":"……不，還是送給你吧。你可以帶走。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GUEST_VOICE_NULL_A","text":{"KOREA":"고, 고마워요. 훌쩍.","JPN":"あ、ありがとうございあす。ぐすん。","ENG":"Thank you. *Sniffle*","TWN":"謝…謝謝你。(擤鼻涕)"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GUEST_VOICE_NULL_A","text":{"KOREA":"……좀 진정이 됐어요. 이제 가볼게요…….","JPN":"……少し落ち着きました。もう行きますね……","ENG":"I feel better now. I’ll be going...","TWN":"……我有冷靜一點了，那我先走囉……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그래. 또 울고 싶어지거든 찾아와. 언제든 어깨 빌려줄 테니까.","JPN":"ええ、泣きたくなった時はまたいらっしゃい。肩なんていつでも貸してあげるから。","ENG":"Okay, come visit me whenever you feel like crying. I will be here for you.","TWN":"好，之後下次想哭的話儘管來找我，我的肩膀借你。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GUEST_VOICE_NULL_A","text":{"KOREA":"흑. 고마워요……!","JPN":"ぐすん。ありがとうございます……！","ENG":"*Sob* Thank you!","TWN":"嗚。謝謝……！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"자……. 이제 왜 이 난장판이 벌어진 건지 말해. 또 무슨 일인데?","JPN":"さて……どうしてこんな騒ぎが起きたのか言え。いったいどういうことだ？","ENG":"Now... Tell me what this is all about. Did you do something again?","TWN":"那……說說到底為什麼會發生這場鬧劇吧，又是怎麼搞的？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"글쎄? 그저 숨겨둔 감정을 드러내는 약물을 넣었을 뿐인걸.","JPN":"さあ？　私はただ隠している感情を表に出すお薬を入れただけよ。","ENG":"Well? All I did was use a drop of this potion that exposes people’s hidden emotions.","TWN":"這個嘛？只是放入幾滴可以釋放出壓抑情感的藥物而已。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"……그게 슬픔이었다니. 좀 짠하네.","JPN":"……それが悲しみだったなんて。ちょっと可哀そうね。","ENG":"And it looks like she had some hidden sadness. I feel sorry for her.","TWN":"……只是我沒想到會這麼難過，好可憐喔。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"슬픔을 숨겨야만 하는 상황이란 건, 그게 뭐든 너무 가혹한 것 같아.","JPN":"悲しみを隠さなければならないなんて、理由がどうあれ苛酷だと思うわ。","ENG":"What makes people hide their sadness? Whatever it is, that's too harsh.","TWN":"竟然必須將自己的悲傷隱藏起來，不管是什麼原因，不覺得很殘忍嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"현대인의 삶이란. 그렇지?","JPN":"これが現代人の人生、なんてね。","ENG":"I guess that’s life these days, right?","TWN":"現代人的生活，大致都是如此吧？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"뭐가 됐든, 손님을 임상시험 대상으로 쓰지 말라고 했을 텐데.","JPN":"とにかく、客を臨床試験の対象として使うなと言ったはずだが。","ENG":"I told you not to experiment on our customers.","TWN":"不管怎樣，我說過不能臨時將客人當作實驗對象吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"대체 몇 번을 말해야 알아들을 거야?","JPN":"いったい何回言えばいいのだ？","ENG":"How many times do I have to tell you?","TWN":"到底要再說多少遍才能聽懂？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"이미 충분히 말 잘 듣는 매니저 아닐까~?","JPN":"もう十分わかっていると思うけど～？","ENG":"Don't you think I am already an obedient supervisor?","TWN":"我應該是個很聽話的經理吧～？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"아니야!!","JPN":"全然わかってない！！","ENG":"NO, YOU’RE NOT!","TWN":"才不是！！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"계속 이상한 약물 타서 만드는데도 손님들이 찾는 게 신기하다, 신기해.","JPN":"毎回変な薬を入れているのに、客が絶えないのが不思議なくらいだ。","ENG":"Why would customers keep coming here, when they are fed weird potions? I don’t get it.","TWN":"而且最奇怪的是，你每次都用奇怪的藥水製作飲料，卻總是有客人光顧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그야 내 손맛이 뛰어난 탓 아니겠어?","JPN":"それは私が淹れたコーヒーが美味しいからじゃない？","ENG":"That’s probably because my food tastes great.","TWN":"這是因為我的手藝太好吧？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"하여간 능글맞기는. 그게 다가 아니잖아?","JPN":"とぼけるな。それがすべてじゃないだろう？","ENG":"You’re sly. I know there’s more than that.","TWN":"你還敢說，你加的不只是藥水吧！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"오오. 역시 점장님은 뭐든 다 아는구나?","JPN":"あら。やっぱり店長はなんでもお見通しなのね。","ENG":"Oh, of course you know everything!","TWN":"喔喔，果然什麼都瞞不過店長？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"사실은 약물에 감칠맛을 더해줄 조미료나 향신료를 추가하거든. 그러니 더 맛있을 수밖에.","JPN":"実はお薬に味に深みが出る調味料や香辛料も追加しているの。\\n美味しくならないはずがないわ。","ENG":"I add MSG to my potions to improve the taste. There’s no way it can’t be good.","TWN":"其實我會在藥水裡邊添加一些增加風味的調料還有香料。所以才會更美味。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"애초에 <color=#ffd34c>맛있어지는 묘약</color>도 내가 만든 거니까. 이게 다 맛에 통달한 이 언니의 재능이지♪","JPN":"そもそも<color=#ffd34c>美味しくなる妙薬</color>だって私が作ったものだし。\\nこれも全部、有能なお姉さんの才能よ♪","ENG":"You know I also made the <color=#ffd34c>Tasty Potion</color>. I am such a talented chef, don’t you agree? ♪","TWN":"一開始調配出<color=#ffd34c>美味秘方</color>的也是我，都是因為我對味道很敏銳吧♪"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"……..","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그거 사실 <color=#ffd34c>맛있어지는 묘약</color>이 아니라 <color=#ffd34c>맛있게 느껴지는 묘약</color>인 거 아냐?","JPN":"実はそれ、<color=#ffd34c>美味しくなる妙薬</color>じゃなくて、<color=#ffd34c>なんでも美味しく感じてしまう妙薬</color>なんじゃないか？","ENG":"Then it’s not actually the <color=#ffd34c>Tasty Potion</color>; it’s more like a <color=#ffd34c>potion that makes you think it’s tasty</color>.","TWN":"但那個其實根本就不是<color=#ffd34c>美味秘方</color>，而是<color=#ffd34c>讓人誤以為美味的妙藥</color>才對吧？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"뭐. 됐어. 그래도 저주가 아니라 좋은 쪽으로 발현되는 약물이니까 다행이지.","JPN":"まあ。良かろう。呪いではなく良い効果が出る薬だからまだましか。","ENG":"Oh, whatever. I don’t care as long as it doesn’t affect people in a bad way like a curse.","TWN":"不過算了。至少不是詛咒，而且效果是好的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그럼, 그럼.","JPN":"そうそう。","ENG":"Sure, sure.","TWN":"當然。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그러고 보니 너. 여기 오기 전엔 전투용 비약만 사용하는 전투 약제사였잖아.","JPN":"そういえばエヴリン。ここに来る前までは戦闘用の秘薬だけを扱う戦闘薬剤師だったじゃないか。","ENG":"But before we came here, you were a combat chemist making battle potions only.","TWN":"不過話說回來，你來這裡之前是調配戰鬥用秘藥的戰鬥藥劑師吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"여기 와선 왠지 시시해졌네.","JPN":"ここに来てからは、なんだかつまらなくなったな。","ENG":"Now you only make boring potions.","TWN":"來到這裡後，怎麼感覺變無趣啦？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"……심경의 변화야 충분히 있을 수 있다지만. 대체 무슨 심보야?","JPN":"……心境の変化なんておかしなことではないがな。いったいどういうつもりだ？","ENG":"I know people can change, but what happened to you?","TWN":"……雖然很有可能是心境上產生變化，但你到底安的是什麼心？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"……후후. 그건.","JPN":"……ふふ、それは。","ENG":"Haha, that’s...","TWN":"呵呵，那是因為……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"GUEST_VOICE_NULL_B","text":{"KOREA":"저어. 실례지만, 여기가 소원을 들어준다는 마녀 카페 맞나요?","JPN":"あの。ごめんなさい。ここが願いを叶えてくれる魔女カフェですか？","ENG":"Excuse me. Is this the Witch Cafe that grants people’s wishes?","TWN":"不好意思，請問這裡是可以達成願望的魔女咖啡廳嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"아니.","JPN":"違う。","ENG":"No.","TWN":"不是。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"얘기라도 들어보자~ 무슨 소원을 빌고 싶길래?","JPN":"話だけでも聞いてみましょうよ。どんなお願いかしら？","ENG":"Come on, let’s hear them out. What is your wish?","TWN":"先聽聽看嘛～你想達成什麼願望？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GUEST_VOICE_NULL_B","text":{"KOREA":"며칠 뒤에 아주 중요한 시험이 있거든요.","JPN":"数日後にとても重要な試験があるんです。","ENG":"I have a very important exam coming up.","TWN":"幾天後有一場非常重要的考試。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"아하. 집중력 오르게 해주는 소원 정도라면 들어줄 수 있을 것 같은데~","JPN":"なるほどね、集中力を上げてほしいってお願いなら叶えてあげられそうだけど～。","ENG":"Oh, I see. I can help you concentrate better when you’re studying.","TWN":"喔喔～如果你的願望是想提升注意力的話，那沒問題喔～"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"GUEST_VOICE_NULL_B","text":{"KOREA":"아뇨. 그런 거 말고요.","JPN":"いえ。そんなのはどうでもいいんです。","ENG":"No, that’s not what I want.","TWN":"不，不是的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"No?","TWN":"嗯？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GUEST_VOICE_NULL_B","text":{"KOREA":"진짜 징글징글하게 따라붙는 라이벌이 한 명 있어서요. 요즘엔 저보다 성적도 좋게 나오고요.","JPN":"実は、気味が悪いくらい私に付きまとうライバルが1人いるんです。\\n最近は私より成績も良いし……","ENG":"I have a rival and she’s doing better than me, these days. I'm sick and tired of her.","TWN":"我有一個討厭的競爭對手，最近他的成績也比我好。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GUEST_VOICE_NULL_B","text":{"KOREA":"아프게 하든 다치든 상관없어요. 그 애가 시험만 못 치르면 돼요.","JPN":"体調を崩すでも、怪我をするでも構いません。その子がテストを受けられないようにしてほしいんです。","ENG":"I don’t care if you hurt her, or make her sick. Just don’t let her take the exam.","TWN":"我希望可以讓他受傷或是生病，反正只要能讓他沒辦法應試就好。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"하? 여기 마녀보다 더 못된 녀석이 있었네?","JPN":"ほう？　ここには魔女よりもっと性格が悪い奴がいたんだな？","ENG":"Hah? How can you be meaner than a witch?","TWN":"蛤？竟然出現一個比魔女還壞的傢伙？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GUEST_VOICE_NULL_B","text":{"KOREA":"네? 제발요! 소원 좀 들어줘요. 제 인생이 걸린 시험이란 말이에요!","JPN":"どうか！　お願いします！　私の人生がかかった大事な試験なんです！","ENG":"Please! Grant my wish! My life depends on this exam!","TWN":"可以嗎？求求你們！請實現我的願望。這場考試會決定我之後的人生！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GUEST_VOICE_NULL_B","text":{"KOREA":"아니면 저주 인형이나, 아프게 만드는 약이든 뭐든 만들어 주시면 제가 직접 할게요!","JPN":"それか、呪いの人形なり、体調を崩す薬なり、なんでもいいので作ってください！\\n私が直接やります！","ENG":"Or just give me something like a voodoo doll or a potion that makes her sick, and I’ll do the rest!","TWN":"還是幫我做一個詛咒娃娃，或是讓人生病的藥，我可以自己下手！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"손님. 우린 그런 건 만들지 않아.","JPN":"ごめんね。私たちはそんなもの作らないのよ。","ENG":"Dear, we don’t make such things.","TWN":"這位客人，我們不會做那種東西。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GUEST_VOICE_NULL_B","text":{"KOREA":"왜요?! 다들 원하지 않아요?","JPN":"どうしてですか！？　他の人たちも欲しがるはずです！","ENG":"Why not? Everyone would want one!","TWN":"為什麼？！不是很有市場嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GUEST_VOICE_NULL_B","text":{"KOREA":"저주 인형만 팔아도 대박날 것 같은데……!","JPN":"呪いの人形だけでも売ったら大儲けできそうなのに……！","ENG":"Voodoo dolls would sell great!","TWN":"光是賣詛咒娃娃就可以賺大錢吧……！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그런 건, 정작 중요할 땐 쓸모가 없거든.","JPN":"そんなものは、いざという時に役に立たないのよ。","ENG":"You should know that such things are useless at the most important moments.","TWN":"那種東西，在最重要的時刻是完全沒用的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"사랑하는 사람을 지킬 수도, 살릴 수도 없어.","JPN":"愛する人を守ることも、生き返らせることもできないわ。","ENG":"They can neither protect nor save the people you love.","TWN":"不能保護或拯救所愛的人。"},"stage":{"bg":"SS_STREGA_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"마찬가지로 라이벌을 아프게 만들어 봤자 네 실력이 오르는 것도 아니고.","JPN":"同じように、ライバルに怪我をさせたってあなたの実力が上がるわけでもないしね。","ENG":"Likewise, hurting your rival won’t get you a good score on the test.","TWN":"同樣的，就算讓競爭對手生病，也不能提高你自己的實力。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"지금 잠깐은 좋을 지 몰라도 해결되는 건 아무것도 없을 거야.","JPN":"ちょっとは良くなるかも知れないけど、解決できることは何もないわ。","ENG":"You might feel better for a while, but in the end, it won’t solve anything.","TWN":"雖然可能會讓你短時間內獲利，但不能從根本上解決問題。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GUEST_VOICE_NULL_B","text":{"KOREA":"그렇지만…….","JPN":"でも……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"나 같으면 이딴 짓으로 시간 낭비할 바에 돌아가서 시험 준비나 열심히 하겠다.","JPN":"そんなことで時間を無駄にするくらいなら、早く帰って試験の準備でもしたほうがましだな。","ENG":"If I were you, I would just go home and study, rather than wasting my time here.","TWN":"如果是我，與其這樣浪費時間，不如回去認真準備考試。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"헛된 망상 그만 하고 저리 썩 꺼져!","JPN":"無駄な妄想はそれくらいにして、さっさと帰れ！","ENG":"Now cut your nonsense and get out!","TWN":"不要再想這些有的沒的，快點走吧！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GUEST_VOICE_NULL_B","text":{"KOREA":"흑…….","JPN":"しくしく……","ENG":"*Sob*","TWN":"嗚……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"잠시만. 이거 가져가.","JPN":"ちょっと待って。これを持って行って。","ENG":"Wait, take this.","TWN":"等等，這個給你。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GUEST_VOICE_NULL_B","text":{"KOREA":"……이게 뭔데요?","JPN":"……これは何でしょうか？","ENG":"What is it?","TWN":"……這是什麼？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"머리를 맑게 만들어주는 티백이야. 우려 마시면 잡념이 사라지고 집중하기 좋을 거야.","JPN":"頭をすっきりさせるお茶よ。飲めば雑念がなくなって、集中しやすくなるわ。","ENG":"This tea will clear your head. It will help you clear your mind and concentrate better.","TWN":"是能讓人頭腦清醒的茶包。回去後泡著喝，就能讓你消除雜念，集中精神。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"준비 잘 해서 정정당당히 잘 보고 오렴. 언니가 맛있는 디저트 만들어줄게♪","JPN":"ちゃんと準備して正々堂々と頑張ってね。私が美味しいスイーツでも作ってあげるから♪","ENG":"Study hard, and do your best in your exam. When you come back, I’ll make you a delightful dessert. ♪","TWN":"希望你能好好準備，正正當當地完成考試。我會為你準備好吃的甜點喔♪"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GUEST_VOICE_NULL_B","text":{"KOREA":"흐읍…… 네, 고마워요.","JPN":"ううっ……はい。ありがとうございます。","ENG":"*Sob* Okay, thank you.","TWN":"嗯……好，謝謝你。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"기분 나쁜데 시험 망치게 저주 걸어버릴까?","JPN":"鬱陶しいから、赤点を取るように呪ってしまおうか？","ENG":"What a creepy girl. I think I should curse her to ruin her exam.","TWN":"真討厭，還是詛咒她考不好怎麼樣？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"너도 상당히 못됐다니까?","JPN":"ラウラは本当に意地悪ね？","ENG":"You are so mean.","TWN":"你也蠻壞的嘛。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"흥. 마녀는 원래 좀 못되게 굴어야 해. 너처럼 물렁하게 대하면 기어오른다고.","JPN":"ふん。魔女はちょっと意地悪なくらいがちょうどいいんだ。\\nエヴリンみたいに優しすぎるとつけあがられるだけだ。","ENG":"Hmpf. A witch should be mean. Being soft won’t do you any good.","TWN":"哼，魔女就是該壞一點。如果都像你那麼溫柔，別人就會爬到你頭上。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"알겠지만, 내가 원래 푸딩 같은 매력이 있어서 말이야~","JPN":"私はプリンみたいに柔らかくて優しいからね～。","ENG":"Well, I’m soft like pudding. And that’s my charm.","TWN":"我知道，但我的魅力不就是像布丁一樣柔軟嗎～"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"딴소리는 됐고. 하려던 대답이나 마저 해.","JPN":"うるさいな。早く質問に答えろ。","ENG":"Knock it off, and just answer my question.","TWN":"別岔開話題，還是先回答剛才的問題吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"……대충 알 것 같긴 하지만. 아까 네가 그 못된 녀석한테 했던 말도 있고.","JPN":"……まあ、さっきの性格が悪い客に言った言葉でなんとなくわかったが。","ENG":"Well, I think I already know the answer, though. From what you said to that mean girl.","TWN":"……雖然我大概也能猜到。畢竟我有聽到你剛剛和那個壞蛋說過的話。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"맞아.","JPN":"そうね。","ENG":"You’re right.","TWN":"沒錯。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"시시한 일상에서 사용하는 약물이야말로 사람들에게 도움이 되는 것 같아서.","JPN":"何でもない平凡な日常で使われるお薬のほうが、人々の役に立っている気がしてね。","ENG":"I feel like all these miscellaneous potions used in everyday life are what actually help people.","TWN":"我覺得能在瑣碎的日常中使用的藥物，才能真正幫助別人。"},"stage":{"bg":"SS_STREGA_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"꼭 과거라도 떠올린 표정이네. 뭐 좋은 과거라고.","JPN":"まるで悪い過去でも思い出したような顔だな。","ENG":"Are you looking back the past? The past is in the past.","TWN":"看你的表情，就像是在回憶過去。可那又不是什麼好的回憶。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"어머나. 역시 라우라는 심리술에 능통하다니까? 마녀가 아니라 족집게야~","JPN":"あら。やっぱりラウラは心理術に長けてるわね？\\n魔女じゃなくて占い師のほうが向いているんじゃない～？","ENG":"Oh, Laura, you read my mind. You’re more like a scryer than a witch.","TWN":"天啊，蘿拉對心理學果然很有研究吧？原來你不是魔女，而是心理學家～"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"헛소리 집어치우고 일이나 해. 농땡이라면 충분히 피웠어.","JPN":"黙って仕事しろ。ズル休みはもう十分だろうが。","ENG":"Cut it out and go back to work. Break time is over.","TWN":"少在那胡說八道，快去做事吧，摸魚摸夠了吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"네, 네. 난 원두나 볶으러 들어가야겠다. 에블린 특제 블렌딩, 기대해줘♪","JPN":"はいはい。私はコーヒー豆でも挽きに行くわ。エヴリン特製ブレンド、楽しみにしていてね♪","ENG":"Okay, I’ll go roast the coffee beans. Please look forward to Evelyn’s Special Blend!","TWN":"好好好。那我要去炒咖啡豆囉，敬請期待伊芙琳特製的混合咖啡♪"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"흥. 아무렇지 않은 척 하기는.","JPN":"ふん。強がりおって。","ENG":"Hmpf. She’s pretending she’s okay.","TWN":"哼。還要裝作如無其事的樣子。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냐옹…….","JPN":"にゃ……","ENG":"Meow...","TWN":"喵……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"시끄러워, 플루토. 영업 끝나고 한 잔 하면서 풀어주면 될 거 아냐.","JPN":"うるさい、プルートー。営業が終わったら一杯やりながら開放してやるから。","ENG":"Shut it, Pluto. I will buy her a drink later to console her.","TWN":"別吵，布魯托。等收店後再邊喝邊聊吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냐아옹~","JPN":"にゃああ～。","ENG":"Meow!","TWN":"喵喵～"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};